// Auto-generated word pool for Wordle (Only 4 and 5 letter words supported)
// The pool is compressed into a single string to save space.
// Words are sorted so that the most common words (and Minecraft words) appear first.
// The first N words are considered valid solutions, but ALL words in the string are valid guesses.
export const compressedWordPool: Record<number, string> = {
    4: '',
    5: ''
};

// We limit the random solution picker to the first N words to prevent obscure words from being the answer.
// N = 500 means the first 500 words (including Minecraft words + top english words) are possible solutions.
const SOLUTION_LIMIT = 500;

export function isValidWord(word: string): boolean {
    const len = word.length;
    const pool = compressedWordPool[len];
    if (!pool) return false;

    // In a compressed string of fixed-length words, check if it's a multiple of length
    const idx = pool.indexOf(word.toLowerCase());
    return idx !== -1 && idx % len === 0;
}

export function getRandomSolution(length: number): string | undefined {
    const pool = compressedWordPool[length];
    if (!pool) return undefined;

    const maxWordsInPool = pool.length / length;
    if (maxWordsInPool === 0) return undefined;

    // Limit the random selection to the top SOLUTION_LIMIT words
    const limit = Math.min(maxWordsInPool, SOLUTION_LIMIT);
    const randomIdx = Math.floor(Math.random() * limit) * length;

    return pool.substring(randomIdx, randomIdx + length);
}
